INSERT INTO public.update_log (title, body, type, created_at) VALUES ('Cadastro de Usuarios', 'Os usuarios agora podem criar contas e se registrar no Glossario. Membros registrados tambem ganharam a capacidade de enviar sugestoes de novos termos e comentarios.', 'app', '2026-03-15 00:00:00');
INSERT INTO public.update_log (title, body, type, created_at) VALUES ('Sistema de Sugestoes', 'Membros registrados podem sugerir novos termos de traducao. Apos analise editorial, os termos podem ser marcados como aprovados e gerenciados pelo painel administrativo.', 'app', '2026-03-20 00:00:00');
INSERT INTO public.update_log (title, body, type, created_at) VALUES ('Categorias do Glossario', 'Foram estruturadas e organizadas as categorias de glossario por tipo sistema e cenario, permitindo filtragem e navegacao mais precisa entre os termos.', 'app', '2026-03-22 00:00:00');
INSERT INTO public.update_log (title, body, type, created_at) VALUES ('Sistema de Selos', 'Implementado um novo sistema visual de selos: Tradicao Oficial para traducoes publicadas pela Gale Force Nine, Rigor Artificio para termos documentados com pre-projeto de traducao, e Sugestao para contribuicoes da comunidade em revisao.', 'app', '2026-03-28 00:00:00');
